import os
import json
import boto3
from typing import Any, Dict, Optional


class SQSPublisher:
    def __init__(self, queue_url: str, region_name: Optional[str] = None):
        self.queue_url = queue_url
        self.sqs = boto3.client("sqs", region_name=region_name or os.getenv("AWS_REGION"))

    def publish(self, user_data: Dict[str, Any]) -> Dict[str, Any]:
        message_body = json.dumps(user_data, ensure_ascii=False)
        return self.sqs.send_message(
            QueueUrl=self.queue_url,
            MessageBody=message_body,
        )


def main():
    queue_url = os.environ["SQS_QUEUE_URL"]
    publisher = SQSPublisher(queue_url=queue_url)

    user_data = {
        "user_id": "12345",
        "name": "Jane Doe",
        "email": "jane.doe@example.com",
        "phone": "+1-555-123-4567",
        "address": {
            "line1": "123 Main St",
            "city": "Springfield",
            "state": "IL",
            "zip": "62704",
            "country": "US",
        },
    }

    response = publisher.publish(user_data)
    print(response)


if __name__ == "__main__":
    main()